 1	import React, { FC } from 'react';
 2	import { v4 as uuidv4 } from 'uuid';
 3	
 4	import { Button } from '@patternfly/react-core';
 5	import { MinusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/minus-circle-icon';
 6	import { PlusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/plus-circle-icon';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	import { NetworkPolicyPort } from '@utils/models';
 9	
10	import PortsDropdown from '../NetworkPolicyPortsDropdown';
11	
12	type NetworkPolicyPortsProps = {
13	  onChange: (ports: NetworkPolicyPort[]) => void;
14	  ports: NetworkPolicyPort[];
15	};
16	const NetworkPolicyPorts: FC<NetworkPolicyPortsProps> = (props) => {
17	  const { onChange, ports } = props;
18	  const { t } = useNetworkingTranslation();
19	
20	  const onSingleChange = (port: NetworkPolicyPort, index: number) => {
21	    onChange([...ports.slice(0, index), port, ...ports.slice(index + 1)]);
22	  };
23	
24	  const onRemove = (index: number) => {
25	    onChange([...ports.slice(0, index), ...ports.slice(index + 1)]);
26	  };
27	
28	  return (
29	    <>
30	      {
31	        <div className="form-group co-create-networkpolicy__ports-list">
32	          <label>{t('Ports')}</label>
33	          <div className="help-block" id="ingress-peers-help">
34	            <p>
35	              {t(
36	                'Add ports to restrict traffic through them. If no ports are provided, your policy will make all ports accessible to traffic.',
37	              )}
38	            </p>
39	          </div>
40	          {ports.map((port, idx) => {
41	            const key = `${port}-${idx}`;
42	            return (
43	              <div className="pf-v6-c-input-group" key={key}>
44	                <PortsDropdown index={idx} onSingleChange={onSingleChange} port={port} />
45	                <input
46	                  aria-describedby="ports-help"
47	                  className="pf-v6-c-form-control"
48	                  data-test="port-input"
49	                  id={`${key}-port`}
50	                  name={`${key}-port`}
51	                  onChange={(event) =>
52	                    onSingleChange({ ...port, port: event.currentTarget.value }, idx)
53	                  }
54	                  placeholder="443"
55	                  value={port.port}
56	                />
57	                <Button
58	                  aria-label={t('Remove port')}
59	                  className="co-create-networkpolicy__remove-port"
60	                  data-test="remove-port"
61	                  onClick={() => onRemove(idx)}
62	                  type="button"
63	                  variant="plain"
64	                >
65	                  <MinusCircleIcon />
66	                </Button>
67	              </div>
68	            );
69	          })}
70	          <div className="co-toolbar__group co-toolbar__group--left co-create-networkpolicy__add-port">
71	            <Button
72	              className="pf-m-link--align-left"
73	              data-test="add-port"
74	              onClick={() => {
75	                onChange([...ports, { key: `port-${uuidv4}`, port: '', protocol: 'TCP' }]);
76	              }}
77	              type="button"
78	              variant="link"
79	            >
80	              <PlusCircleIcon className="co-icon-space-r" />
81	              {t('Add port')}
82	            </Button>
83	          </div>
84	        </div>
85	      }
86	    </>
87	  );
88	};
89	
90	export default NetworkPolicyPorts;

